head.script:
scwin.vCurDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");  // 서버를 기준으로 현재 날짜 반환
scwin.vQryStDt = scwin.vCurDate.substring(0, 6) + "01";  // 조회시작일자(현재 날짜가 포함된 달의 시작 일자)
scwin.vQryEndDt = scwin.vCurDate.substring(0, 6) + new Date(scwin.vCurDate.substring(0, 4), scwin.vCurDate.substring(4, 6) , 0).getDate();  // 조회종료일자(현재 날짜가 포함된 달의 마지막 일자)
//scwin.strPreDate = WebSquare.date.dateAdd(scwin.vCurDate, -2);
scwin.strPreDate = $c.date.addMonth(scwin.vCurDate, -1);

scwin.onpageload = function() {
    const codeOptions = [
        { grpCd : "FS262", compID : "lc_pchsAdmitClsCd"},
        //{ grpCd : "LO102", compID : "gr_conversionUnitDTOList:basisUnit", opt : {"range" : "2,L"}},
    ];
    $c.data.setCommonCode(codeOptions);
};

scwin.onUdcCompleted = function() {
    $p.setTimeout(function() {
		scwin.f_SetDefaultData();		
		$c.gus.cfDisableAllBtn();

        ///임시        
        // 248365   20181020 20181030

    }, {"delay":50});
};

//-------------------------------------------------------------------------
// Default Data Setting
//-------------------------------------------------------------------------
scwin.f_SetDefaultData = function () {		
    ica_wrkDtSt.setValue(scwin.vQryStDt);  // 운송일자시작		
    ica_wrkDtEnd.setValue(scwin.vQryEndDt);  // 운송일자종료
    ica_pchsIntendDt.setValue(scwin.vCurDate);;  // 매입예정일자		
    //cfSetIMEModeActiveObjects([ed_wrkPlNm, ed_pchsDeptNm, ed_pchsClntNm, ed_admitPicNm, ed_rmk]);  // IME 한글 처리
    $c.gus.cfDisableObjects([ica_pchsIntendDt,  ed_rmk, ed_certiNo, btn_certiNo, ed_hid_rmk]);
    //lc_pchsAdmitClsCd.MaxLength = "50";		
    lc_pchsAdmitClsCd.setSelectedIndex(0);

    ed_pchsClntNo.focus();
}

//-------------------------------------------------------------------------
// 철송비용승인(일자별) 조회
//-------------------------------------------------------------------------
scwin.f_RetrieveDateEachRailroadCostList = async function () {		
    // 검색조건 필수 입력 체크, 동일 날짜 포함 여부 체크
    var chk = await $c.gus.cfValidate([ed_pchsClntNo, ica_wrkDtSt, ica_wrkDtEnd, ed_pchsClntNo]);
    if (!chk) {
        return;
    }

    var chkDate = await $c.gus.cfIsAfterDate(ica_wrkDtSt.getValue(), ica_wrkDtEnd.getValue());
    if (!chkDate) {
        $c.win.alert("조회 시작일자는 종료일자 보다 이전 날짜 이어야 합니다.");
        ica_wrkDtSt.focus();
        return;
    }

    //tr_searchDateEachRailroadCostList.post();
    $c.sbm.execute(sbm_searchDateEachRailroadCostList);
}

//-------------------------------------------------------------------------
// 철송비용승인(TYPE별) 조회
//-------------------------------------------------------------------------
scwin.f_RetrieveTypeEachRailroadCostList = function (row) {	
    /*
    if (ds_searchTypeEachRailroadCostList.getRowCount() == 0) {
        var GAUCE_DATASET_HEADER = "wrkDt:STRING(8)"                      // 운송일자
                                    + ",dptWrkPlCd:STRING(5)"                // 출발지                          
                                    + ",arvWrkPlCd:STRING(5)"                // 도착지      
                                    + ",pchsAdmitClsCd:STRING(6)"            // 동부승인구분
                                    + ",pchsCertiNo:STRING(11)"              // 매입거래명세서번호
                                    + ",pchsClntNo:STRING(6)"                // 매입거래처
                                    + ",pchsDeptCd:STRING(8)"                // 매입점소
                                    + ",admitPic:STRING(8)";                 // 승인담당자 

        ds_searchTypeEachRailroadCostList.SetDataHeader(GAUCE_DATASET_HEADER);
        ds_searchTypeEachRailroadCostList.AddRow();					
    }
    */

    dma_searchTypeEachRailroadCostList.set("wrkDt", ds_dateEachRailroadCostList.getCellData(row, "wrkDt"));
    dma_searchTypeEachRailroadCostList.set("dptWrkPlCd", ds_dateEachRailroadCostList.getCellData(row, "dptWrkPlCd"));
    dma_searchTypeEachRailroadCostList.set("arvWrkPlCd", ds_dateEachRailroadCostList.getCellData(row, "arvWrkPlCd"));
    dma_searchTypeEachRailroadCostList.set("pchsAdmitClsCd", ds_dateEachRailroadCostList.getCellData(row, "pchsAdmitClsCd"));
    dma_searchTypeEachRailroadCostList.set("pchsCertiNo", ds_dateEachRailroadCostList.getCellData(row, "pchsCertiNo"));
    dma_searchTypeEachRailroadCostList.set("pchsClntNo", ds_dateEachRailroadCostList.getCellData(row, "pchsClntNo"));
    dma_searchTypeEachRailroadCostList.set("pchsDeptCd", ds_dateEachRailroadCostList.getCellData(row, "pchsDeptCd"));
    dma_searchTypeEachRailroadCostList.set("admitPic", ds_dateEachRailroadCostList.getCellData(row, "admitPic"));

    //tr_searchTypeEachRailroadCostList.post();
    $c.sbm.execute(sbm_searchTypeEachRailroadCostList);
}

//-------------------------------------------------------------------------
// 신규매입승인 등록
//-------------------------------------------------------------------------
scwin.f_NewPurchaseAdmission = async function () {	
    // Data 변경 여부 조회
    if (ds_dateEachRailroadCostList.getModifiedIndex().length == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["자료"]);
        return;
    }

    // 매입승인구분(FS262)이 02:승인이 아닌 경우
    var pchsAdmitClsCd = "";
    for (var i=0; i < ds_dateEachRailroadCostList.getRowCount(); i++) {		
        pchsAdmitClsCd = ds_dateEachRailroadCostList.getCellData(i, "pchsAdmitClsCd");

        if (ds_dateEachRailroadCostList.getCellData(i, "chk") == "T") {	
            if (pchsAdmitClsCd == "02") {	
                $c.win.alert("매입승인구분이 미승인, 보류인 경우만 가능합니다.");
                return;
            }		
        }
    }

    // 매입예정일자 체크
    if (! await $c.gus.cfValidate([ica_pchsIntendDt])) {
        return;
    }		

    if (await $c.win.confirm(MSG_CM_CRM_001)) {  // 저장하시겠습니까?		
        dma_purchaseCerti.set("selpchItemCd", "0134");  // 매출입항목코드(철송임)
        dma_purchaseCerti.set("pchsGoodsPatternCd", "01");  // 매입품목유형코드(CONTAINER단위)

        dma_purchaseCerti.set("pchsDeptCd", ed_pchsDeptCd.getValue());
        dma_purchaseCerti.set("pchsClntNo", ed_pchsClntNo.getValue());

        console.log(dma_purchaseCerti.getJSON());

        /*
        tr_saveDateEachRailroadCostList.KeyValue = "Servlet(I:IN_DS1=dma_purchaseCerti, I:IN_DS2=ds_dateEachRailroadCostList)";
        tr_saveDateEachRailroadCostList.Action = "/ds.fs.adjm.pchscerticoll.RegistRailroadCostNewAdmissionCMD.do";								
        tr_saveDateEachRailroadCostList.Post();				    
        */
        $c.sbm.execute(sbm_NewPurchaseAdmission);
    }
}

//-------------------------------------------------------------------------
// 추가매입승인 등록
//-------------------------------------------------------------------------
scwin.f_AdditionPurchaseAdmission = async function () {
    // Data 변경 여부 조회
    if (ds_dateEachRailroadCostList.getModifiedIndex().length == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["자료"]);
        return;
    }

    // 매입승인구분(FS262)이 02:승인이 아닌 경우
    var pchsAdmitClsCd = "";
    for (var i=0; i < ds_dateEachRailroadCostList.getRowCount(); i++) {		
        pchsAdmitClsCd = ds_dateEachRailroadCostList.getCellData(i, "pchsAdmitClsCd");

        if (ds_dateEachRailroadCostList.getCellData(i, "chk") == "T") {	
            if (pchsAdmitClsCd == "02") {	
                $c.win.alert("매입승인구분이 미승인, 보류인 경우만 가능합니다.");
                return;
            }		
        }
    }		

    // 거래명세서번호 체크
    if (! await $c.gus.cfValidate([ed_certiNo])) {
        return;
    }

    if (await $c.win.confirm(MSG_CM_CRM_001)) {  // 저장하시겠습니까?		
        dma_purchaseCerti.set("selpchItemCd", "0134");  // 매출입항목코드(철송임)
        dma_purchaseCerti.set("pchsGoodsPatternCd", "01");  // 매입품목유형코드(CONTAINER단위)

        dma_purchaseCerti.set("pchsDeptCd", ed_pchsDeptCd.getValue());
        /*
        tr_saveDateEachRailroadCostList.KeyValue = "Servlet(I:IN_DS1=dma_purchaseCerti, I:IN_DS2=ds_dateEachRailroadCostList)";
        tr_saveDateEachRailroadCostList.Action = "/ds.fs.adjm.pchscerticoll.RegistRailroadCostAdditionAdmissionCMD.do";								
        tr_saveDateEachRailroadCostList.Post();				    
        */
        $c.sbm.execute(sbm_AdditionPurchaseAdmission);
    }
}

//-------------------------------------------------------------------------
// 매입승인취소 등록
//-------------------------------------------------------------------------
scwin.f_PurchaseAdmissionCancel = async function () {	
    // Data 변경 여부 조회
    if (ds_dateEachRailroadCostList.getModifiedIndex().length == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["자료"]);
        return;
    }

    // 매입승인구분(FS262)이 02:승인인 경우와 매입확정 이전인 경우
    var pchsAdmitClsCd = "";
    var pchsEvidYn = "";		
    for (var i=0; i < ds_dateEachRailroadCostList.getRowCount(); i++) {		
        pchsAdmitClsCd = ds_dateEachRailroadCostList.getCellData(i, "pchsAdmitClsCd");
        pchsEvidYn = ds_dateEachRailroadCostList.getCellData(i, "pchsEvidYn");

        if (ds_dateEachRailroadCostList.getCellData(i, "chk") == "T") {	
            if (pchsAdmitClsCd != "02") {	
                $c.win.alert("매입승인구분이 승인인 경우만 가능합니다.");
                return;
            }	
            if (pchsEvidYn == "Y") {	
                $c.win.alert("매입확정 이전인 경우만 가능합니다.");
                return;
            }
        }
    }				

    if (await $c.win.confirm(MSG_CM_CRM_001)) {  // 저장하시겠습니까?	
        /*
        tr_saveDateEachRailroadCostList.KeyValue = "Servlet(I:IN_DS1=ds_dateEachRailroadCostList)";
        tr_saveDateEachRailroadCostList.Action = "/ds.fs.adjm.pchscerticoll.RegistRailroadCostAdmissionCancelCMD.do";								
        tr_saveDateEachRailroadCostList.Post();				    
        */
        $c.sbm.execute(sbm_PurchaseAdmissionCancel);
    }
}

//-------------------------------------------------------------------------
// 거래명세서번호 검색
//------------------------------------------------------------------------- 
scwin.f_OpenCertiNoPopUp = async function () {
    var args = new Array();

    if (ds_dateEachRailroadCostList.getRowCount() == 0) {
        $c.win.alert(MSG_CM_ERR_003);
        return;
    }

    if (!await $c.gus.cfValidate([ed_pchsClntNo])) {
        return;
    }		
    /*
    args["pchsDeptCd"] = ed_pchsDeptCd.Text;  // 매입부서
    args["pchsClntNo"] = ed_pchsClntNo.Text;  // 매입거래처
    args["selpchItemCd"] = "0121";  // 매출입항목코드(중기임차료)
    args["pchsGoodsPatternCd"] = "03";  // 매입품목유형코드(중기)		
    args["pchsIntendDtSt"] = ds_dateEachRailroadCostList.NameMin('wrkDt',0,0).toDate().firstDate().format("YYYYMMDD");  // 운송일자 Min(특정일자의 첫번째 날 리턴)
    args["pchsIntendDtEnd"] = ds_dateEachRailroadCostList.NameMax('wrkDt',0,0).toDate().lastDate().format("YYYYMMDD");  // 운송일자 Max(특정일자의 마지막 날 리턴)

    var popupResult = window.showModalDialog('/ds/fs/adjm/fs_102_01_16p.jsp?paramTitle=거래명세서번호 검색',args,"dialogWidth:500px;dialogHeight:550px;status:No");
    */
    var pchsIntendDtSt = 99999999;
    var pchsIntendDtEnd = 0;
    for(var i=0; i < ds_dateEachRailroadCostList.getRowCount(); i++){
        if(ds_dateEachRailroadCostList.getCellData(i, "wrkDt") < pchsIntendDtSt ){
            pchsIntendDtSt = ds_dateEachRailroadCostList.getCellData(i, "wrkDt");
        }
        if(ds_dateEachRailroadCostList.getCellData(i, "wrkDt") > pchsIntendDtEnd ){
            pchsIntendDtEnd = ds_dateEachRailroadCostList.getCellData(i, "wrkDt");
        }
    }
    if(pchsIntendDtSt == 0) pchsIntendDtSt = "";
    if(pchsIntendDtEnd == 0) pchsIntendDtEnd = "";

    var win_url = "/ui/ds/fs/adjm/fs_102_01_16p.xml";

    var opts = scwin.opts || {};
    opts.modal = true;
    opts.type = "browserPopup";
    opts.id = scwin.popupID || "pupup";
    opts.width = 900;
    opts.height = 400;
    opts.popupName = '거래명세서번호 검색';

    var param = {
        pchsDeptCd : ed_pchsDeptCd.getValue(),
        pchsClntNo : ed_pchsClntNo.getValue(),
        selpchItemCd : "0135",
        pchsGoodsPatternCd : "01",
        pchsIntendDtSt : pchsIntendDtSt,
        pchsIntendDtEnd : pchsIntendDtEnd
    }

    rtnList = await $c.win.openPopup(win_url, opts, param);
    console.log("rtnList : " , rtnList);    

    // Modal Dialog를 리턴값 없이 닫을 경우에 대비해
    if (rtnList != null) {
        ed_certiNo.setValue(rtnList.certiNo);
        ed_hid_rmk.setValue(rtnList.rmk);
    }    
}

//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {
    // 선언부
    var rtnList  = new Array();  // 공통POP-UP -> 요청화면 

    switch (disGubun) {
        case 1:  			
            // 매입거래처 팝업			
            rtnList = udc_pchsClntNo.cfCommonPopUp(scwin.callbackClntList,pCode.trim(),pName,pClose,null,null,null,null,null,null,null,null,null,null,pAllSearch,null);

            //cfSetReturnValue(rtnList, ed_pchsClntNo, ed_pchsClntNm);  // 매입거래처코드, 매입거래처명								
            break;	

        case 2:  			
            // 매입점소 팝업			
            rtnList = udc_pchsDeptCd.cfCommonPopUp(scwin.callbackLobranInfo,pCode.trim(),pName,pClose,null,null,null,null,null,null,null,null,null,null,pAllSearch,null);	  				  			

            //cfSetReturnValue(rtnList, ed_pchsDeptCd, ed_pchsDeptNm);  // 매입점소코드, 매입점소명				
            break;	

        case 3:
            // 승인담당자 팝업			
            rtnList = udc_admitPic.cfCommonPopUp(scwin.callbackEmpInfo,pCode.trim(),pName,pClose,null,null,null,null,null,null,null,null,null,null,pAllSearch,null);	  				  			

            //cfSetReturnValue(rtnList, ed_admitPic, ed_admitPicNm);  // 사번, 성명				
            break;

        default:
            break;
    }
}

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    /*
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj))
        return;
    */
    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    var pVal = $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true)
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    // inObj가 코드명 필드일 경우 팝업
    else
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
}

//-------------------------------------------------------------------------
// 검색영역 Field Clear함.
//-------------------------------------------------------------------------
scwin.f_InitObjects = function () {
    $c.gus.cfInitObjects(tb_mainData);
    scwin.f_SetDefaultData();
}

scwin.callbackLobranInfo = function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_pchsDeptCd, ed_pchsDeptNm);  // 매입점소코드, 매입점소명				
}

scwin.callbackClntList = function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_pchsClntNo, ed_pchsClntNm);  // 매입거래처코드, 매입거래처명								
}

scwin.callbackEmpInfo = function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_admitPic, ed_admitPicNm);  // 사번, 성명				
}

scwin.udc_pchsClntNo_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(1, ed_pchsClntNo.getValue(), ed_pchsClntNm.getValue(), 'F', 'F');
};

scwin.udc_pchsClntNo_onblurCodeEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(ed_pchsClntNo, ed_pchsClntNm, 1);
};

scwin.udc_pchsClntNo_onviewchangeNameEvent = function (info) {
    if(ed_pchsClntNm.getValue() == "") {
        ed_pchsClntNo.setValue("");
    } else {
        scwin.f_chkOpenCommonPopUp(ed_pchsClntNm, ed_pchsClntNo, 1, false);
    }
};

scwin.udc_pchsDeptCd_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(2, ed_pchsDeptCd.getValue(), ed_pchsDeptNm.getValue(), 'F', 'T');
};

scwin.udc_pchsDeptCd_onblurCodeEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(ed_pchsDeptCd, ed_pchsDeptNm, 2);
};

scwin.udc_pchsDeptCd_onviewchangeNameEvent = function (info) {
    scwin.f_chkOpenCommonPopUp(ed_pchsDeptNm, ed_pchsDeptCd, 2, false);
};

scwin.udc_admitPic_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(3, ed_admitPic.getValue(), ed_admitPicNm.getValue(), 'F', 'F');
};

scwin.udc_admitPic_onblurCodeEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(ed_admitPic, ed_admitPicNm, 3);
};

scwin.udc_admitPic_onviewchangeNameEvent = function (info) {
    scwin.f_chkOpenCommonPopUp(ed_admitPicNm, ed_admitPic, 3, false);
};

scwin.btn_retrieve_onclick = function (e) {
    scwin.f_RetrieveDateEachRailroadCostList();
};

scwin.btn_fieldClear_onclick = function (e) {
    scwin.f_InitObjects();
};



scwin.sbm_searchDateEachRailroadCostList_submitdone = function (e) {
    var rowCnt = ds_dateEachRailroadCostList.getRowCount();
    spa_cnt1.setValue(rowCnt);

    // 건수/총금액 계산
    //scwin.f_GetPchsAdmitCntTotAmt();

    //gr_dateEachRailroadCostList.ColumnProp('chk','HeadCheck') = "false";
    ica_pchsIntendDt.setValue(scwin.vCurDate);;  // 매입예정일자		
    ed_rmk.setValue(""); // 비고
    ed_certiNo.setValue(""); // 거래명세서번호
    ed_hid_rmk.setValue("");  // 비고

    if (rowCnt == 0) {
        ds_typeEachRailroadCostList.removeAll();
        spa_cnt1.setValue(0);

        $c.gus.cfDisableAllBtn();
        $c.gus.cfDisableObjects([ica_pchsIntendDt, ed_rmk, btn_certiNo, ed_hid_rmk]);
        $c.win.alert(MSG_CM_ERR_003);  // 해당되는 자료가 존재하지 않습니다
    } else {
        $c.gus.cfEnableAllBtn();
        $c.gus.cfEnableObjects([ica_pchsIntendDt, ed_rmk, btn_certiNo]);
        gr_dateEachRailroadCostList.setFocusedCell(0, 0);
    }
};

scwin.sbm_searchTypeEachRailroadCostList_submitdone = function (e) {
    var rowCnt = ds_typeEachRailroadCostList.getRowCount();
    spa_cnt2.setValue(rowCnt);
};

scwin.sbm_NewPurchaseAdmission_submitdone = function (e) {
    console.log(e.responseJSON.resultDataSet);
    if(e.responseJSON.resultDataSet[0].Code == 0) {
        scwin.f_RetrieveDateEachRailroadCostList();
   	    $c.win.alert(MSG_CM_INF_001);	// 성공적으로 저장하였습니다
    } else {
        if(e.responseJSON.resultDataSet[1] != null && e.responseJSON.resultDataSet[1].Msg != null && e.responseJSON.resultDataSet[1].Msg != "") {
            $c.win.alert(e.responseJSON.resultDataSet[1].Msg);
        }
    }
};

scwin.sbm_AdditionPurchaseAdmission_submitdone = function (e) {
    console.log(e.responseJSON.resultDataSet);
    if(e.responseJSON.resultDataSet[0].Code == 0) {
        scwin.f_RetrieveDateEachRailroadCostList();
   	    $c.win.alert(MSG_CM_INF_001);	// 성공적으로 저장하였습니다
    } else {
        if(e.responseJSON.resultDataSet[1] != null && e.responseJSON.resultDataSet[1].Msg != null && e.responseJSON.resultDataSet[1].Msg != "") {
            $c.win.alert(e.responseJSON.resultDataSet[1].Msg);
        }
    }
};

scwin.sbm_PurchaseAdmissionCancel_submitdone = function (e) {
    console.log(e.responseJSON.resultDataSet);
    if(e.responseJSON.resultDataSet[0].Code == 0) {
        scwin.f_RetrieveDateEachRailroadCostList();
   	    $c.win.alert(MSG_CM_INF_001);	// 성공적으로 저장하였습니다
    } else {
        if(e.responseJSON.resultDataSet[1] != null && e.responseJSON.resultDataSet[1].Msg != null && e.responseJSON.resultDataSet[1].Msg != "") {
            $c.win.alert(e.responseJSON.resultDataSet[1].Msg);
        }
    }
};

scwin.gr_dateEachRailroadCostList_onrowindexchange = function (rowIndex, oldRow) {
    scwin.f_RetrieveTypeEachRailroadCostList(rowIndex);
};

scwin.btn_Create1_onclick = function (e) {
    scwin.f_PurchaseAdmissionCancel();
};

scwin.btn_Create2_onclick = function (e) {
    scwin.f_NewPurchaseAdmission();
};

scwin.btn_Create3_onclick = function (e) {
    scwin.f_AdditionPurchaseAdmission();
};

scwin.btn_certiNo_onclick = function (e) {
    scwin.f_OpenCertiNoPopUp();
};

