scwin.onkeyup = function (e) {
    this.setValue(e.target.value.toUpperCase());
};

scwin.excelDown1 = function () {
    const options = {
        fileName : "철송비용승인(일자별).xlsx", //[default : excel.xlsx] options.fileName 값이 없을 경우 default값 세팅
        sheetName : "철송비용승인(일자별)",
        startRowIndex : 2,
        startColumnIndex : 0,
    };

    // 타이틀
    const infoArr = [{
                    rowIndex : 0, colIndex : 0, rowSpan : 1, colSpan : 14, text : "철송비용승인(일자별)", textAlign : "center", 
                    drawBorder : false, fontSize : "18px"
                },
                {
                    rowIndex : 1, colIndex : 0, rowSpan : 1, colSpan : 14, textAlign : "left", drawBorder : false
                }];


    $c.data.downloadGridViewExcel(gr_dateEachRailroadCostList, options, infoArr);
}

